#compdef gh

_gh() {
  local curcontext="$curcontext" state line ret=1
  typeset -A opt_args

  _arguments -C -S -s \
    '(- :)--help[show help]' \
    '(- :)--version[show gh version]' \
    '1:command:->commands' \
    '*::arg:->args' && ret=0

  case $state in
    commands)
      local -a commands=(
        'auth:Authenticate gh and git with GitHub'
        'browse:Open repositories, issues, pull requests, and more in the browser'
        'codespace:Connect to and manage codespaces'
        'gist:Manage gists'
        'issue:Manage issues'
        'pr:Manage pull requests'
        'release:Manage releases'
        'repo:Manage repositories'
        'run:View details about workflow runs'
        'workflow:View details about GitHub Actions workflows'
        'alias:Create command shortcuts'
        'api:Make an authenticated GitHub API request'
        'completion:Generate shell completion scripts'
        'config:Manage configuration for gh'
        'extension:Manage gh extensions'
        'label:Manage labels'
        'ruleset:View info about repo rulesets'
        'search:Search for repositories, issues, and pull requests'
        'secret:Manage GitHub secrets'
        'ssh-key:Manage SSH keys'
        'status:Print information about relevant issues, pull requests, and notifications'
        'variable:Manage GitHub Actions variables'
        'gpg-key:Manage GPG keys'
        'cache:Manage GitHub Actions caches'
      )
      _describe 'command' commands && ret=0
      ;;
    args)
      curcontext="${curcontext%:*:*}:gh-$line[1]:"
      case $line[1] in
        pr) _gh_pr ;;
        auth) _gh_auth ;;
        browse) _gh_browse ;;
        codespace) _gh_codespace ;;
        gist) _gh_gist ;;
        issue) _gh_issue ;;
        release) _gh_release ;;
        repo) _gh_repo ;;
        run) _gh_run ;;
        workflow) _gh_workflow ;;
        alias) _gh_alias ;;
        api) _gh_api ;;
        completion) _gh_completion ;;
        config) _gh_config ;;
        extension) _gh_extension ;;
        label) _gh_label ;;
        ruleset) _gh_ruleset ;;
        search) _gh_search ;;
        secret) _gh_secret ;;
        ssh-key) _gh_ssh_key ;;
        status) _gh_status ;;
        variable) _gh_variable ;;
        gpg-key) _gh_gpg_key ;;
        cache) _gh_cache ;;
      esac
      ;;
  esac
  return ret
}

# ── pr ──────────────────────────────────────────────────────────────────────────

_gh_pr() {
  local curcontext="$curcontext" state line ret=1
  typeset -A opt_args

  _arguments -C -S -s \
    '(- :)--help[show help]' \
    '(-R --repo)'{-R,--repo}'[select another repository]:repo:' \
    '1:command:->commands' \
    '*::arg:->args' && ret=0

  case $state in
    commands)
      local -a commands=(
        'create:Create a pull request'
        'list:List pull requests in a repository'
        'merge:Merge a pull request'
        'view:View a pull request'
        'checkout:Check out a pull request in git'
        'close:Close a pull request'
        'comment:Add a comment to a pull request'
        'diff:View changes in a pull request'
        'edit:Edit a pull request'
        'ready:Mark a pull request as ready for review'

