50	    <thead>
51	      <tr>
52	        <th style="width:65%">Query</th>
53	        <th style="width:18%">Should Trigger</th>
54	        <th style="width:10%">Actions</th>
55	      </tr>
56	    </thead>
57	    <tbody id="eval-body"></tbody>
58	  </table>
59	
60	  <p class="summary" id="summary"></p>
61	
62	  <script>
63	    const EVAL_DATA = __EVAL_DATA_PLACEHOLDER__;
64	
65	    let evalItems = [...EVAL_DATA];
66	
67	    function render() {
68	      const tbody = document.getElementById('eval-body');
69	      tbody.innerHTML = '';
70	
71	      // Sort: should-trigger first, then should-not-trigger
72	      const sorted = evalItems
73	        .map((item, origIdx) => ({ ...item, origIdx }))
74	        .sort((a, b) => (b.should_trigger ? 1 : 0) - (a.should_trigger ? 1 : 0));
75	
76	      let lastGroup = null;
77	      sorted.forEach(item => {
78	        const group = item.should_trigger ? 'trigger' : 'no-trigger';
79	        if (group !== lastGroup) {
80	          const headerRow = document.createElement('tr');
81	          headerRow.className = 'section-header';
82	          headerRow.innerHTML = `<td colspan="3">${item.should_trigger ? 'Should Trigger' : 'Should NOT Trigger'}</td>`;
83	          tbody.appendChild(headerRow);
84	          lastGroup = group;
85	        }
86	
87	        const idx = item.origIdx;
88	        const tr = document.createElement('tr');
89	        tr.innerHTML = `
90	          <td><textarea class="query-input" onchange="updateQuery(${idx}, this.value)">${escapeHtml(item.query)}</textarea></td>
91	          <td>
92	            <label class="toggle">
93	              <input type="checkbox" ${item.should_trigger ? 'checked' : ''} onchange="updateTrigger(${idx}, this.checked)">
94	              <span class="slider"></span>
95	            </label>
96	            <span style="margin-left:8px;font-size:0.8rem;color:#b0aea5">${item.should_trigger ? 'Yes' : 'No'}</span>
97	          </td>
98	          <td><button class="btn-delete" onclick="deleteRow(${idx})">Delete</button></td>
99	        `;
100	        tbody.appendChild(tr);
101	      });
102	      updateSummary();
103	    }
104	
105	    function escapeHtml(text) {
106	      const div = document.createElement('div');
107	      div.textContent = text;
108	      return div.innerHTML;
109	    }
110	
111	    function updateQuery(idx, value) { evalItems[idx].query = value; updateSummary(); }
112	    function updateTrigger(idx, value) { evalItems[idx].should_trigger = value; render(); }
113	    function deleteRow(idx) { evalItems.splice(idx, 1); render(); }
114	
115	    function addRow() {
116	      evalItems.push({ query: '', should_trigger: true });
117	      render();
118	      const inputs = document.querySelectorAll('.query-input');
119	      inputs[inputs.length - 1].focus();
120	    }
121	
122	    function updateSummary() {
123	      const trigger = evalItems.filter(i => i.should_trigger).length;
124	      const noTrigger = evalItems.filter(i => !i.should_trigger).length;
125	      document.getElementById('summary').textContent =
126	        `${evalItems.length} queries total: ${trigger} should trigger, ${noTrigger} should not trigger`;
127	    }
128	
129	    function exportEvalSet() {
130	      const valid = evalItems.filter(i => i.query.trim() !== '');
131	      const data = valid.map(i => ({ query: i.query.trim(), should_trigger: i.should_trigger }));
132	      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
133	      const url = URL.createObjectURL(blob);
134	      const a = document.createElement('a');
135	      a.href = url;
136	      a.download = 'eval_set.json';
137	      document.body.appendChild(a);
138	      a.click();
139	      document.body.removeChild(a);
140	      URL.revokeObjectURL(url);
141	    }
142	
143	    render();
144	  </script>
145	</body>
146	</html>
